1	#!/usr/bin/env node
2	/**
3	 * chat_retrieve.js — 定点检索 OKKI 聊天记录
4	 *
5	 * 模式:
6	 *   pointer  --mode=pointer --cid=<cid> --timestamps=ts1,ts2 --context=5
7	 *            按时间戳定位消息，返回消息 + 上下文
8	 *   search   --mode=search   --cid=<cid> --keyword="xxx" --context=3
9	 *            按关键词搜索消息，返回匹配 + 上下文
10	 *
11	 * 输出: 纯文本到 stdout（供人阅读或 AI 消费）
12	 */
13	
14	const fs = require("fs");
15	const path = require("path");
16	
17	// ── 参数解析 ──────────────────────────────────────────────
18	const args = process.argv.slice(2);
19	const getArg = (name) => {
20	  const prefix = `--${name}=`;
21	  const found = args.find((a) => a.startsWith(prefix));
22	  return found ? found.slice(prefix.length) : null;
23	};
24	const hasArg = (name) => args.includes(`--${name}`);
25	
26	const mode = getArg("mode");
27	const cid = getArg("cid");
28	const keyword = getArg("keyword");
29	const timestampsRaw = getArg("timestamps");
30	const context = parseInt(getArg("context") || "3", 10);
31	
32	if (!mode || !cid) {
33	  console.error("用法:");
34	  console.error("  node chat_retrieve.js --mode=pointer --cid=<cid> --timestamps=ts1,ts2 [--context=5]");
35	  console.error("  node chat_retrieve.js --mode=search   --cid=<cid> --keyword=<kw>  [--context=3]");
36	  process.exit(1);
37	}
38	
39	// ── 路径解析 ──────────────────────────────────────────────
40	const DATA_DIR = path.resolve(__dirname, "..", "data");
41	const CHAT_HISTORY_DIR = path.join(DATA_DIR, "chat_history");
42	
43	// cid 格式: {aliId}-{accountId}#11011@icbu
44	// 文件名格式: {aliId}-{accountId}_11011_icbu.json
45	function cidToFilename(cidStr) {
46	  const match = cidStr.match(/^(.+)#(\d+)@(\w+)$/);
47	  if (!match) return null;
48	  const [, left, channel, platform] = match;
49	  return `${left}_${channel}_${platform}.json`;
50	}
51	
52	const filename = cidToFilename(cid);
53	if (!filename) {
54	  console.error(`无法解析 cid: ${cid}`);
55	  process.exit(1);
56	}
57	
58	const filepath = path.join(CHAT_HISTORY_DIR, filename);
59	if (!fs.existsSync(filepath)) {
60	  console.error(`聊天文件不存在: ${filepath}`);
61	  console.error(`  cid: ${cid}`);
62	  process.exit(1);
63	}
64	
65	// ── 读取聊天记录 ──────────────────────────────────────────
66	const raw = JSON.parse(fs.readFileSync(filepath, "utf-8"));
67	const allMessages = raw.messages || [];
68	
69	// 过滤系统消息，只保留真实消息
70	function isSystemMessage(msg) {
71	  try {
72	    return msg.message?.extension?.systemMessage === true ||
73	           msg.message?.extension?.basicMessageInfo?.includes('"systemMessage":true');
74	  } catch {
75	    return false;
76	  }
77	}
78	
79	function getMessageText(msg) {
80	  try {
81	    return msg.message?.content?.text?.content || "";
82	  } catch {
83	    return "";
84	  }
85	}
86	
87	function getMessageTime(msg) {
88	  try {
89	    return msg.message?.createAt || 0;
90	  } catch {
91	    return 0;
92	  }
93	}
94	
95	function getSenderTag(msg) {
96	  try {
97	    const uid = msg.message?.sender?.uid || "";
98	    // 我方 uid 包含 "2500000853693"（accountId）
99	    return uid.includes("2500000853693") ? "我" : "客";
100	  } catch {
101	    return "?";
102	  }
103	}
104	
105	function getMsgId(msg) {
106	  try {
107	    return msg.message?.messageId || "?";
108	  } catch {
109	    return "?";
110	  }
111	}
112	
113	// ── 辅助: 格式化时间 ──────────────────────────────────────
114	function fmtTime(ts) {
115	  const d = new Date(ts);
116	  const pad = (n) => String(n).padStart(2, "0");
117	  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
118	}
119	
120	// ── 辅助: 输出消息 ────────────────────────────────────────
121	function formatMessage(msg) {
122	  const ts = getMessageTime(msg);
123	  const sender = getSenderTag(msg);
124	  const text = getMessageText(msg);
125	  const msgId = getMsgId(msg);
126	  return `[${fmtTime(ts)}] [${sender}] (MsgID:${msgId})\n${text}`;
127	}
128	
129	// ── 指针模式 ──────────────────────────────────────────────
130	function runPointer() {
131	  if (!timestampsRaw) {
132	    console.error("pointer 模式需要 --timestamps=ts1,ts2,...");
133	    process.exit(1);
134	  }
135	
136	  const targets = timestampsRaw.split(",").map((t) => parseInt(t.trim(), 10));
137	  const realMessages = allMessages.filter((m) => !isSystemMessage(m));
138	
139	  if (realMessages.length === 0) {
140	    console.log(`客户: ${raw.name || cid}`);
141	    console.log(`消息总数: ${allMessages.length} (无真实消息)`);
142	    return;
143	  }
144	
145	  console.log(`客户: ${raw.name || cid}`);
146	  console.log(`消息总数: ${allMessages.length} (真实: ${realMessages.length})`);
147	  console.log(`上下文窗口: ±${context} 条\n`);
148	
149	  for (const targetTs of targets) {
150	    // 找最接近的消息索引
151	    let bestIdx = 0;
152	    let bestDist = Infinity;
153	    for (let i = 0; i < realMessages.length; i++) {
154	      const dist = Math.abs(getMessageTime(realMessages[i]) - targetTs);
155	      if (dist < bestDist) {
156	        bestDist = dist;
157	        bestIdx = i;
158	      }
159	    }
160	
161	    const start = Math.max(0, bestIdx - context);
162	    const end = Math.min(realMessages.length - 1, bestIdx + context);
163	
164	    console.log(`── 定位: ${fmtTime(targetTs)} → 最近消息 #${bestIdx + 1}/${realMessages.length} (偏移 ${bestDist > 0 ? (getMessageTime(realMessages[bestIdx]) > targetTs ? "+" : "-") + Math.round(bestDist / 1000 / 60) + "min" : "精确匹配"}) ──`);
165	
166	    for (let i = start; i <= end; i++) {
167	      const marker = i === bestIdx ? ">>>" : "   ";
168	      console.log(`${marker} ${formatMessage(realMessages[i])}`);
169	      console.log("");
170	    }
171	  }
172	}
173	
174	// ── 搜索模式 ──────────────────────────────────────────────
175	function runSearch() {
176	  if (!keyword) {
177	    console.error("search 模式需要 --keyword=<关键词>");
178	    process.exit(1);
179	  }
180	
181	  const kwLower = keyword.toLowerCase();
182	  const realMessages = allMessages.filter((m) => !isSystemMessage(m));
183	
184	  // 找所有匹配的消息索引
185	  const matchIndices = [];
186	  for (let i = 0; i < realMessages.length; i++) {
187	    const text = getMessageText(realMessages[i]).toLowerCase();
188	    if (text.includes(kwLower)) {
189	      matchIndices.push(i);
190	    }
191	  }
192	
193	  console.log(`客户: ${raw.name || cid}`);
194	  console.log(`消息总数: ${allMessages.length} (真实: ${realMessages.length})`);
195	  console.log(`关键词: "${keyword}" → ${matchIndices.length} 条匹配\n`);
196	
197	  if (matchIndices.length === 0) {
198	    console.log("未找到匹配消息。");
199	    return;
200	  }
201	
202	  // 合并重叠的上下文窗口
203	  const windows = [];
204	  for (const idx of matchIndices) {
205	    const start = Math.max(0, idx - context);
206	    const end = Math.min(realMessages.length - 1, idx + context);
207	
208	    if (windows.length > 0 && start <= windows[windows.length - 1].end + 1) {
209	      // 合并到前一个窗口
210	      windows[windows.length - 1].end = Math.max(windows[windows.length - 1].end, end);
211	      windows[windows.length - 1].hits.push(idx);
212	    } else {
213	      windows.push({ start, end, hits: [idx] });
214	    }
215	  }
216	
217	  for (const win of windows) {
218	    console.log(`── 匹配 ${win.hits.length} 条 (消息 #${win.start + 1}~#${win.end + 1}) ──`);
219	    for (let i = win.start; i <= win.end; i++) {
220	      const isHit = win.hits.includes(i);
221	      const marker = isHit ? ">>>" : "   ";
222	      console.log(`${marker} ${formatMessage(realMessages[i])}`);
223	      console.log("");
224	    }
225	  }
226	}
227	
228	// ── 执行 ──────────────────────────────────────────────────
229	if (mode === "pointer") {
230	  runPointer();
231	} else if (mode === "search") {
232	  runSearch();
233	} else {
