1	#!/usr/bin/env node
2	/**
3	 * scan_updates.js — 状态卡自动扫描（防腐烂机制）
4	 *
5	 * 每次 /okki 启动时运行，检测：
6	 *   1. 聊天有新消息但状态卡未更新 → 标记"待检查"
7	 *   2. NOW 客户超过 7 天未 checked → 提醒
8	 *   3. SOON 客户超过 30 天未 checked → 标注"可能过期"
9	 *
10	 * 用法:
11	 *   node scripts/scan_updates.js
12	 *   node scripts/scan_updates.js --json    (JSON 输出，供其他脚本消费)
13	 */
14	
15	const fs = require("fs");
16	const path = require("path");
17	
18	const DATA_DIR = path.resolve(__dirname, "..", "data");
19	const BRIEFS_DIR = path.join(DATA_DIR, "briefs");
20	const CHAT_DIR = path.join(DATA_DIR, "chat_history");
21	
22	const NOW_STALE_DAYS = 7;
23	const SOON_STALE_DAYS = 30;
24	
25	// ── 辅助 ──────────────────────────────────────────────────
26	
27	function cidToFilename(cidStr) {
28	  const match = cidStr.match(/^(.+)#(\d+)@(\w+)$/);
29	  if (!match) return null;
30	  const [, left, channel, platform] = match;
31	  return `${left}_${channel}_${platform}.json`;
32	}
33	
34	function fmtDays(n) {
35	  if (n === 0) return "今天";
36	  if (n === 1) return "昨天";
37	  if (n < 30) return `${n}天前`;
38	  if (n < 365) return `${Math.round(n / 30)}月前`;
39	  return `${Math.round(n / 365)}年前`;
40	}
41	
42	// ── 解析 frontmatter ─────────────────────────────────────
43	
44	function parseFrontmatter(content) {
45	  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
46	  if (!match) return null;
47	  const fm = {};
48	  for (const line of match[1].split("\n")) {
49	    const kv = line.match(/^(\w+):\s*(.+)$/);
50	    if (kv) fm[kv[1]] = kv[2].trim();
51	  }
52	  return fm;
53	}
54	
55	// ── 主扫描逻辑 ───────────────────────────────────────────
56	
57	function scan() {
58	  if (!fs.existsSync(BRIEFS_DIR)) {
59	    console.error("briefs 目录不存在: " + BRIEFS_DIR);
60	    return { summary: {}, items: [] };
61	  }
62	
63	  const files = fs.readdirSync(BRIEFS_DIR).filter((f) => f.endsWith(".md"));
64	  const results = [];
65	
66	  for (const file of files) {
67	    const filePath = path.join(BRIEFS_DIR, file);
68	    const content = fs.readFileSync(filePath, "utf-8");
69	    const fm = parseFrontmatter(content);
70	    if (!fm || !fm.cid) continue;
71	
72	    const cid = fm.cid;
73	    const heat = fm.heat;
74	    const checked = fm.checked ? new Date(fm.checked + "T00:00:00Z") : null;
75	    const stage = fm.stage || "未知";
76	    const country = fm.country || "未知";
77	
78	    // 从文件名提取客户名
79	    const nameFromFile = file.replace(/^[\d-]+_/, "").replace(/\.md$/, "");
80	    const displayName = nameFromFile || "未知";
81	
82	    // 查找聊天文件
83	    const chatFilename = cidToFilename(cid);
84	    const chatPath = chatFilename ? path.join(CHAT_DIR, chatFilename) : null;
85	    let chatLatestTime = null;
86	    let chatTotalMessages = 0;
87	    let hasNewerMessages = false;
88	
89	    if (chatPath && fs.existsSync(chatPath)) {
90	      try {
91	        const raw = JSON.parse(fs.readFileSync(chatPath, "utf-8"));
92	        chatTotalMessages = raw.messages?.length || 0;
93	        if (raw.messages && raw.messages.length > 0) {
94	          // 消息按时间倒序（最新在前），索引 0 即最新
95	          chatLatestTime = raw.messages[0].message?.createAt || null;
96	          if (chatLatestTime && checked) {
97	            hasNewerMessages = chatLatestTime > checked.getTime();
98	          }
99	        }
100	      } catch (e) {
101	        // 聊天文件损坏，跳过
102	      }
103	    }
104	
105	    // 计算 checked 距今几天
106	    const daysSinceChecked = checked
107	      ? Math.round((Date.now() - checked.getTime()) / 86400000)
108	      : null;
109	
110	    // 判定标记
111	    const flags = [];
112	    if (hasNewerMessages) {
113	      flags.push("有新消息");
114	    }
115	    if (heat === "NOW" && daysSinceChecked !== null && daysSinceChecked > NOW_STALE_DAYS) {
116	      flags.push(`过期${daysSinceChecked}天未检查`);
117	    }
118	    if (heat === "SOON" && daysSinceChecked !== null && daysSinceChecked > SOON_STALE_DAYS) {
119	      flags.push("可能过期");
120	    }
121	
122	    results.push({
123	      file,
124	      cid,
125	      displayName,
126	      country,
127	      heat,
128	      stage,
129	      checked: fm.checked,
130	      daysSinceChecked,
131	      chatLatestTime: chatLatestTime ? new Date(chatLatestTime).toISOString().slice(0, 10) : null,
132	      chatTotalMessages,
133	      hasNewerMessages,
134	      flags,
135	    });
136	  }
137	
138	  // 汇总
139	  const nowNew = results.filter((r) => r.heat === "NOW" && r.hasNewerMessages).length;
140	  const soonNew = results.filter((r) => r.heat === "SOON" && r.hasNewerMessages).length;
141	  const nowStale = results.filter((r) => r.heat === "NOW" && r.flags.some((f) => f.includes("过期"))).length;
142	  const soonStale = results.filter((r) => r.heat === "SOON" && r.flags.some((f) => f.includes("可能过期"))).length;
143	  const needsAttention = results.filter((r) => r.flags.length > 0);
144	
145	  return {
146	    summary: {
147	      totalCards: results.length,
148	      nowCards: results.filter((r) => r.heat === "NOW").length,
149	      soonCards: results.filter((r) => r.heat === "SOON").length,
150	      coldCards: results.filter((r) => r.heat === "COLD").length,
151	      nowNew,
152	      soonNew,
153	      nowStale,
154	      soonStale,
155	      needsAttention: needsAttention.length,
156	    },
157	    items: results.sort((a, b) => {
158	      // NOW first, then SOON, then COLD; within same heat, needsAttention first
159	      const heatOrder = { NOW: 0, SOON: 1, COLD: 2 };
160	      const ha = heatOrder[a.heat] ?? 9;
161	      const hb = heatOrder[b.heat] ?? 9;
162	      if (ha !== hb) return ha - hb;
163	      const fa = a.flags.length > 0 ? 0 : 1;
164	      const fb = b.flags.length > 0 ? 0 : 1;
165	      return fa - fb;
166	    }),
167	  };
168	}
169	
170	// ── 输出 ──────────────────────────────────────────────────
171	
172	const result = scan();
173	const { summary, items } = result;
174	const jsonMode = process.argv.includes("--json");
175	
176	if (jsonMode) {
177	  console.log(JSON.stringify(result, null, 2));
178	  process.exit(0);
179	}
180	
181	console.log("═══════════════════════════════════════");
182	console.log("  scan_updates.js — 状态卡扫描报告");
183	console.log("═══════════════════════════════════════");
184	console.log(`扫描时间: ${new Date().toISOString().slice(0, 10)}`);
185	console.log(`状态卡总数: ${summary.totalCards} (NOW:${summary.nowCards} SOON:${summary.soonCards} COLD:${summary.coldCards})`);
186	console.log("");
187	
188	if (summary.needsAttention === 0) {
189	  console.log("✓ 所有状态卡均为最新，无需处理。");
190	} else {
191	  console.log(`⚠ ${summary.needsAttention} 张状态卡需要注意：`);
192	  if (summary.nowNew > 0) console.log(`  ${summary.nowNew} 个 NOW 客户有新消息待检查`);
193	  if (summary.soonNew > 0) console.log(`  ${summary.soonNew} 个 SOON 客户有新消息待检查`);
194	  if (summary.nowStale > 0) console.log(`  ${summary.nowStale} 个 NOW 客户超过 ${NOW_STALE_DAYS} 天未检查`);
195	  if (summary.soonStale > 0) console.log(`  ${summary.soonStale} 个 SOON 客户可能过期`);
196	  console.log("");
197	
198	  // 表头
199	  const header = `${"客户".padEnd(22)} ${"热度".padEnd(6)} ${"checked".padEnd(12)} ${"最新消息".padEnd(12)} ${"标记"}`;
200	  console.log(header);
201	  console.log("-".repeat(header.length + 10));
202	
203	  for (const item of items) {
204	    if (item.flags.length === 0) continue;
205	    const name = item.displayName.padEnd(22).substring(0, 22);
206	    const heat = item.heat.padEnd(6);
207	    const checked = (item.checked || "?").padEnd(12);
208	    const latest = (item.chatLatestTime || "无文件").padEnd(12);
209	    const flags = item.flags.join(", ");
210	    console.log(`${name} ${heat} ${checked} ${latest} ${flags}`);
211	  }
212	}
213	
214	console.log("");
215	console.log(`提示: ${summary.needsAttention} 张待检查 → AI 逐张对比状态卡 vs 新消息，更新状态卡内容`);
