1	#!/usr/bin/env node
2	/**
3	 * gen_dashboard.js — 从状态卡生成看板表格
4	 *
5	 * 读取 data/briefs/*.md，生成分组排序的客户看板。
6	 *
7	 * 用法:
8	 *   node scripts/gen_dashboard.js              → Markdown 表格到 stdout
9	 *   node scripts/gen_dashboard.js --html       → HTML 到 stdout
10	 *   node scripts/gen_dashboard.js -o board.md  → 输出到文件
11	 */
12	
13	const fs = require("fs");
14	const path = require("path");
15	
16	const DATA_DIR = path.resolve(__dirname, "..", "data");
17	const BRIEFS_DIR = path.join(DATA_DIR, "briefs");
18	const LATEST_PATH = path.join(DATA_DIR, "tm_conversations_latest.json");
19	
20	const args = process.argv.slice(2);
21	const htmlMode = args.includes("--html");
22	const outFile = (() => {
23	  const idx = args.indexOf("-o");
24	  return idx >= 0 ? args[idx + 1] : null;
25	})();
26	
27	// ── 解析 frontmatter ─────────────────────────────────────
28	function parseFrontmatter(content) {
29	  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
30	  if (!match) return {};
31	  const fm = {};
32	  for (const line of match[1].split("\n")) {
33	    const kv = line.match(/^(\w+):\s*(.+)$/);
34	    if (kv) fm[kv[1]] = kv[2].trim();
35	  }
36	  return fm;
37	}
38	
39	// ── 从状态卡正文提取字段 ─────────────────────────────────
40	
41	function extractSection(content, heading) {
42	  const re = new RegExp(`## ${heading}\\s*\\n([\\s\\S]*?)(?=\\n## |$)`, "i");
43	  const match = content.match(re);
44	  return match ? match[1].trim() : "";
45	}
46	
47	function extractTalkSummary(content) {
48	  // 从"最近动态"中提取最后一句话（→ 前面的摘要）
49	  const section = extractSection(content, "最近动态");
50	  // 取 → 前面的最后一行有意义文本
51	  const lines = section.split("\n").filter((l) => l.trim() && !l.startsWith("[初稿]") && !l.startsWith("→"));
52	  if (lines.length > 0) {
53	    const last = lines[lines.length - 1];
54	    // 清理日期前缀和 MsgID
55	    const cleaned = last.replace(/^-\s*\d{4}-\d{2}-\d{2}\s*(我|客):\s*/, "").replace(/（MsgID:[\w.]+）$/, "");
56	    return cleaned.substring(0, 80);
57	  }
58	  // fallback: return the → line content
59	  const arrowLine = section.match(/→\s*(.+)/);
60	  return arrowLine ? arrowLine[1].substring(0, 80) : "";
61	}
62	
63	function extractNextStep(content) {
64	  const section = extractSection(content, "下一步");
65	  const arrowLine = section.match(/→(?:\s*\[初稿\]\s*)?(.+)/);
66	  return arrowLine ? arrowLine[1].trim().substring(0, 60) : section.substring(0, 60);
67	}
68	
69	function extractFirstContact(content) {
70	  const section = extractSection(content, "画像");
71	  const match = section.match(/(\d{4}-\d{2}-\d{2})\s*首次联系/);
72	  return match ? match[1] : null;
73	}
74	
75	// ── 获取最后联系时间（从 tm_conversations_latest.json） ──
76	function loadContactTimes() {
77	  if (!fs.existsSync(LATEST_PATH)) return {};
78	  const data = JSON.parse(fs.readFileSync(LATEST_PATH, "utf-8"));
79	  const map = {};
80	  for (const conv of data.conversations || []) {
81	    map[conv.cid] = {
82	      lastContactTime: conv.lastContactTime,
83	      daysSinceLastContact: conv.preComputed?.daysSinceLastContact ?? null,
84	    };
85	  }
86	  return map;
87	}
88	
89	// ── 主逻辑 ──────────────────────────────────────────────────
90	
91	function buildDashboard() {
92	  if (!fs.existsSync(BRIEFS_DIR)) {
93	    console.error("briefs 目录不存在");
94	    return [];
95	  }
96	
97	  const contactMap = loadContactTimes();
98	  const files = fs.readdirSync(BRIEFS_DIR).filter((f) => f.endsWith(".md"));
99	  const rows = [];
100	
101	  for (const file of files) {
102	    const content = fs.readFileSync(path.join(BRIEFS_DIR, file), "utf-8");
103	    const fm = parseFrontmatter(content);
104	    if (!fm.cid) continue;
105	
106	    // 客户名：从 H1 或文件名提取
107	    const h1Match = content.match(/^#\s+(.+)$/m);
108	    const nameFromFile = file.replace(/^[\d-]+_/, "").replace(/\.md$/, "");
109	    const name = h1Match ? h1Match[1].trim() : nameFromFile;
110	
111	    // 最后联系天数
112	    const contact = contactMap[fm.cid];
113	    const daysSinceLastContact = contact?.daysSinceLastContact ?? null;
114	
115	    // 最后联系显示
116	    let lastContactDisplay = "?";
117	    if (daysSinceLastContact !== null) {
118	      if (daysSinceLastContact === 0) lastContactDisplay = "今天";
119	      else if (daysSinceLastContact === 1) lastContactDisplay = "昨天";
120	      else if (daysSinceLastContact < 30) lastContactDisplay = `${daysSinceLastContact}天前`;
121	      else lastContactDisplay = `${Math.round(daysSinceLastContact / 30)}月前`;
122	    }
123	
124	    const talkSummary = extractTalkSummary(content);
125	    const nextStep = extractNextStep(content);
126	
127	    rows.push({
128	      name,
129	      country: fm.country || "?",
130	      heat: fm.heat || "COLD",
131	      stage: fm.stage || "未知",
132	      lastContact: lastContactDisplay,
133	      daysSinceLastContact: daysSinceLastContact ?? 999,
134	      talkSummary,
135	      nextStep,
136	      cid: fm.cid,
137	      file,
138	      checked: fm.checked || "?",
139	    });
140	  }
141	
142	  // 排序：NOW → SOON → COLD，同热度内按最后联系时间升序
143	  const heatOrder = { NOW: 0, SOON: 1, COLD: 2 };
144	  rows.sort((a, b) => {
145	    const ha = heatOrder[a.heat] ?? 9;
146	    const hb = heatOrder[b.heat] ?? 9;
147	    if (ha !== hb) return ha - hb;
148	    return a.daysSinceLastContact - b.daysSinceLastContact;
149	  });
150	
151	  return rows;
152	}
153	
154	// ── 渲染 ──────────────────────────────────────────────────
155	
156	function renderMarkdown(rows) {
157	  const now = new Date().toISOString().slice(0, 10);
158	  let md = `# OKKI 客户看板\n\n`;
159	  md += `> 生成时间: ${now} | NOW:${rows.filter((r) => r.heat === "NOW").length}人 SOON:${rows.filter((r) => r.heat === "SOON").length}人 COLD:${rows.filter((r) => r.heat === "COLD").length}人\n\n`;
160	
161	  // 表头
162	  md += `| 客户 | 国家 | 热度 | 阶段 | 最后联系 | 聊到哪了 | 下一步 |\n`;
163	  md += `|------|------|------|------|----------|----------|--------|\n`;
164	
165	  let lastHeat = "";
166	  for (const r of rows) {
167	    if (r.heat !== lastHeat) {
168	      lastHeat = r.heat;
169	      md += `| **── ${r.heat} ──** | | | | | | |\n`;
170	    }
171	    // 截断长文本
172	    const summary = r.talkSummary.length > 50 ? r.talkSummary.substring(0, 48) + "…" : r.talkSummary;
173	    const step = r.nextStep.length > 40 ? r.nextStep.substring(0, 38) + "…" : r.nextStep;
174	    const heatIcon = r.heat === "NOW" ? "🔴" : r.heat === "SOON" ? "🟡" : "⚪";
175	    md += `| ${r.name} | ${r.country} | ${heatIcon} ${r.heat} | ${r.stage} | ${r.lastContact} | ${summary} | ${step} |\n`;
176	  }
177	
178	  return md;
179	}
180	
181	function renderHTML(rows) {
182	  const now = new Date().toISOString().slice(0, 10);
183	  const heatIcon = (h) => h === "NOW" ? "🔴" : h === "SOON" ? "🟡" : "⚪";
184	
185	  let html = `<!DOCTYPE html>
186	<html lang="zh-CN">
187	<head>
188	<meta charset="UTF-8">
189	<meta name="viewport" content="width=device-width, initial-scale=1.0">
190	<title>OKKI 客户看板 — ${now}</title>
191	<style>
192	  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; margin: 20px; color: #333; }
193	  h1 { font-size: 1.5em; }
194	  .meta { color: #666; font-size: 0.9em; margin-bottom: 20px; }
195	  table { border-collapse: collapse; width: 100%; font-size: 0.9em; }
196	  th { background: #f5f5f5; padding: 10px 8px; text-align: left; border-bottom: 2px solid #ddd; position: sticky; top: 0; }
197	  td { padding: 8px; border-bottom: 1px solid #eee; vertical-align: top; }
198	  tr:hover td { background: #fafafa; }
199	  .heat-now { color: #d32f2f; font-weight: bold; }
200	  .heat-soon { color: #f57c00; }
201	  .heat-cold { color: #999; }
202	  .section-row td { background: #f0f0f0; font-weight: bold; padding: 6px 8px; font-size: 0.85em; color: #666; }
203	  .summary { max-width: 250px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
204	  .step { max-width: 180px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
205	</style>
206	</head>
207	<body>
208	<h1>OKKI 客户看板</h1>
209	<p class="meta">生成时间: ${now} | NOW:${rows.filter((r) => r.heat === "NOW").length}人 SOON:${rows.filter((r) => r.heat === "SOON").length}人 COLD:${rows.filter((r) => r.heat === "COLD").length}人</p>
210	<table>
211	<thead><tr><th>客户</th><th>国家</th><th>热度</th><th>阶段</th><th>最后联系</th><th>聊到哪了</th><th>下一步</th></tr></thead>
212	<tbody>
213	`;
214	
215	  let lastHeat = "";
216	  for (const r of rows) {
217	    if (r.heat !== lastHeat) {
218	      lastHeat = r.heat;
219	      html += `<tr class="section-row"><td colspan="7">── ${r.heat} ──</td></tr>\n`;
220	    }
221	    const heatClass = r.heat === "NOW" ? "heat-now" : r.heat === "SOON" ? "heat-soon" : "heat-cold";
222	    const summary = (r.talkSummary || "").replace(/</g, "&lt;");
223	    const step = (r.nextStep || "").replace(/</g, "&lt;");
224	    html += `<tr>
225	  <td>${r.name}</td>
226	  <td>${r.country}</td>
227	  <td class="${heatClass}">${heatIcon(r.heat)} ${r.heat}</td>
228	  <td>${r.stage}</td>
229	  <td>${r.lastContact}</td>
230	  <td class="summary" title="${summary}">${summary}</td>
231	  <td class="step" title="${step}">${step}</td>
232	</tr>\n`;
233	  }
234	
235	  html += `</tbody></table></body></html>`;
236	  return html;
237	}
238	
239	// ── 执行 ──────────────────────────────────────────────────
240	
241	const rows = buildDashboard();
242	
243	if (rows.length === 0) {
244	  console.log("无状态卡数据。请先运行 batch_gen_briefs.js");
245	  process.exit(1);
246	}
247	
248	const output = htmlMode ? renderHTML(rows) : renderMarkdown(rows);
249	
250	if (outFile) {
251	  fs.writeFileSync(outFile, output, "utf-8");
252	  console.log(`看板已保存: ${outFile}`);
253	} else {
254	  console.log(output);
255	}
