23	const COUNTRY_MAP = {
24	  US: "美国", GH: "加纳", CM: "喀麦隆", ZA: "南非", CD: "刚果民主共和国",
25	  CI: "科特迪瓦", ZM: "赞比亚", IQ: "伊拉克", SA: "沙特阿拉伯", AE: "阿联酋",
26	  SD: "苏丹", EG: "埃及", OM: "阿曼", BH: "巴林", KW: "科威特", QA: "卡塔尔",
27	  LB: "黎巴嫩", JO: "约旦", PS: "巴勒斯坦", SY: "叙利亚", YE: "也门",
28	  IN: "印度", PK: "巴基斯坦", UK: "英国", FR: "法国", DE: "德国",
29	  ES: "西班牙", IT: "意大利", NL: "荷兰", CA: "加拿大", AR: "阿根廷",
30	  TG: "多哥", KE: "肯尼亚", TZ: "坦桑尼亚", SN: "塞内加尔", RU: "俄罗斯",
31	  KZ: "哈萨克斯坦", UZ: "乌兹别克斯坦", JP: "日本", CN: "中国", HK: "香港",
32	  VN: "越南", IL: "以色列", VE: "委内瑞拉", BR: "巴西",
33	};
34	
35	// ── 过滤黑名单 ──────────────────────────────────────────
36	const SKIP_NAMES = [
37	  "assistant eva", "assistanteva", // OKKI AI bot
38	  "leon scott kennedy", // obvious spam
39	];
40	
41	const SKIP_KEYWORDS = ["鸭梨"]; // spam message content
42	
43	function shouldSkip(result) {
44	  if (SKIP_NAMES.includes(result.name.toLowerCase().trim())) return true;
45	  for (const kw of SKIP_KEYWORDS) {
46	    if (result.lastMsgPreview && result.lastMsgPreview.includes(kw)) return true;
47	  }
48	  return false;
49	}
50	
51	// ── 辅助 ──────────────────────────────────────────────────
52	
53	function cidToFilename(cidStr) {
54	  const match = cidStr.match(/^(.+)#(\d+)@(\w+)$/);
55	  if (!match) return null;
56	  const [, left, channel, platform] = match;
57	  return `${left}_${channel}_${platform}.json`;
58	}
59	
60	function safeFilename(name, cid) {
61	  // cid prefix + sanitized name
62	  const shortCid = cid.split("#")[0].replace(/[@.]/g, "_");
63	  const safeName = name.replace(/[\/\\:*?"<>|]/g, "-").replace(/\s+/g, "-");
64	  return `${shortCid}_${safeName}.md`;
65	}
66	
67	function isSystemMessage(msg) {
68	  try {
69	    const ext = msg.message?.extension;
70	    if (ext?.systemMessage === true) return true;
71	    const bmi = ext?.basicMessageInfo;
72	    if (typeof bmi === "string" && bmi.includes('"systemMessage":true')) return true;
73	    return false;
74	  } catch { return false; }
75	}
76	
77	function getMsgText(msg) {
78	  try { return msg.message?.content?.text?.content || ""; } catch { return ""; }
79	}
80	
81	function getMsgTime(msg) {
82	  try { return msg.message?.createAt || 0; } catch { return 0; }
83	}
84	
85	function senderIsUs(msg) {
86	  try { return (msg.message?.sender?.uid || "").includes(OUR_UID); } catch { return false; }
87	}
88	
89	function getMsgId(msg) {
90	  try { return msg.message?.messageId || ""; } catch { return ""; }
91	}
92	
93	function fmtDate(ts) {
94	  const d = new Date(ts);
95	  const pad = (n) => String(n).padStart(2, "0");
96	  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
97	}
98	
99	function fmtTime(ts) {
100	  const d = new Date(ts);
101	  const pad = (n) => String(n).padStart(2, "0");
102	  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
103	}
104	
105	// ── 判定阶段（基于聊天内容） ──────────────────────────────
106	function detectStage(messages) {
107	  const all = messages.map((m) => getMsgText(m).toLowerCase()).join(" ");
108	  if (/(payment|付款|deposit|定金|invoice|PI|proforma)/.test(all) && /(paid|付了|已付|done)/.test(all)) return "已成交（终态）";
109	  if (/(tracking|物流|shipment|shipped|已发货|提单|B\/L)/.test(all)) return "已发货/在途";
110	  if (/(ready|ready to ship|备好|ship.*soon|about to ship)/.test(all)) return "待发货";
111	  if (/(payment|付款|deposit|定金|balance|余款|pay)/i.test(all)) return "待付款";
112	  if (/(price|报价|usd|dollar|\$|单价|quotation|quote)/.test(all)) return "报价已发";
113	  if (/(sample|样品|打样)/.test(all)) return "样品阶段";
114	  if (/(negotiate|谈判|discount|折扣|better price|便宜)/.test(all)) return "谈判中";
115	  if (/(catalog|pattern|design|style|color|size)/.test(all)) return "需求探索";
116	  return "需求探索";
117	}
118	
119	// ── 生成动态摘要 ──────────────────────────────────────────
120	function generateRecentSummary(realMsgs) {
121	  const recent = realMsgs.slice(0, Math.min(5, realMsgs.length));
122	  const lines = [];
123	  for (const msg of recent.reverse()) { // 时间正序
124	    const ts = getMsgTime(msg);
125	    const sender = senderIsUs(msg) ? "我" : "客";
126	    const text = getMsgText(msg).substring(0, 200).replace(/\n/g, " ");
127	    const msgId = getMsgId(msg);
128	    if (text.trim()) {
129	      lines.push(`- ${fmtDate(ts)} ${sender}: ${text}（MsgID:${msgId}）`);
130	    }
131	  }
132	  return lines.join("\n");
133	}
134	
135	// ── 提取关键数字 ──────────────────────────────────────────
136	function extractKeyNumbers(realMsgs) {
137	  const nums = [];
138	  for (const msg of realMsgs) {
139	    const text = getMsgText(msg);
140	    const ts = getMsgTime(msg);
141	    const sender = senderIsUs(msg) ? "我" : "客";
142	    const msgId = getMsgId(msg);
143	
144	    // 报价
145	    const priceMatch = text.match(/(\$\s*[\d.]+)\s*(\/pc|per piece|USD|每件|单价)?/gi);
146	    if (priceMatch) {
147	      for (const p of priceMatch) {
148	        if (!nums.some((n) => n.includes(p))) {
149	          nums.push(`- 报价：${p.trim()}（${fmtDate(ts)}，${sender}，MsgID:${msgId}）`);
150	        }
151	      }
152	    }
153	
154	    // 数量
155	    const qtyMatch = text.match(/(\d+)\s*(pieces|pcs|件|个|条|套)/gi);
156	    if (qtyMatch) {
157	      for (const q of qtyMatch) {
158	        if (!nums.some((n) => n.includes(q))) {
159	          nums.push(`- 数量：${q.trim()}（${fmtDate(ts)}，${sender}，MsgID:${msgId}）`);
160	        }
161	      }
162	    }
163	  }
164	  return nums.slice(0, 8).join("\n"); // 最多 8 条
165	}
166	
167	// ── 生成下一步建议 ────────────────────────────────────────
168	function generateNextStep(result, realMsgs) {
169	  const days = result.daysSinceLastContact;
170	  const lastSender = result.lastSender;
171	
172	  if (result.reason.includes("超期")) {
173	    return `→ [初稿] 客户等待超过${days}天未回复，建议尽快处理。${lastSender === "客" ? "检查客户最后消息内容并回复" : "评估是否需要再次跟进"}`;
174	  }
175	  if (result.stage === "样品阶段") {
176	    return "→ [初稿] 确认样品进度，推动下一步（反馈→修改→大货）";
177	  }
178	  if (result.stage === "待付款") {
179	    return "→ [初稿] 确认付款状态，必要时发送付款提醒";
180	  }
181	  if (result.stage === "待发货") {
182	    return "→ [初稿] 确认发货安排，如已发货则更新运单号";
183	  }
184	  return "→ [初稿] 查看完整聊天记录后确定具体行动方向";
185	}
186	
187	// ── 主逻辑 ──────────────────────────────────────────────────
188	
189	if (!fs.existsSync(HEAT_PATH)) {
190	  console.error("请先运行 batch_classify_heat.js");
191	  process.exit(1);
192	}
193	
194	const heatData = JSON.parse(fs.readFileSync(HEAT_PATH, "utf-8"));
195	const nowCustomers = heatData.results.filter((r) => r.heat === "NOW" && !shouldSkip(r));
196	
197	console.log(`NOW 客户: ${nowCustomers.length}人 (已过滤机器人/垃圾)`);
198	console.log(`开始生成状态卡...\n`);
199	
200	let generated = 0;
201	let failed = 0;
202	
203	for (const cust of nowCustomers) {
204	  const filename = cidToFilename(cust.cid);
205	  if (!filename) { failed++; continue; }
206	  const chatPath = path.join(CHAT_DIR, filename);
207	  if (!fs.existsSync(chatPath)) { failed++; continue; }
208	
209	  let raw;
210	  try { raw = JSON.parse(fs.readFileSync(chatPath, "utf-8")); }
211	  catch { failed++; continue; }
212	
213	  const allMsgs = raw.messages || [];
214	  const realMsgs = allMsgs.filter((m) => !isSystemMessage(m));
215	  if (realMsgs.length === 0) { failed++; continue; }
216	
217	  // 消息时间倒序，取最近 READ_MSG_COUNT 条
218	  const recentMsgs = realMsgs.slice(0, READ_MSG_COUNT);
219	
220	  // 首次联系时间（最旧消息的时间）
221	  const firstMsgTime = getMsgTime(realMsgs[realMsgs.length - 1]);
222	
223	  // 重新判定阶段（基于更全面的消息）
224	  const stage = detectStage(recentMsgs);
225	
226	  // 构建状态卡
227	  const countryName = COUNTRY_MAP[cust.country] || cust.country;
228	  const safeFile = safeFilename(cust.name, cust.cid);
229	  const filePath = path.join(BRIEFS_DIR, safeFile);
230	
231	  // 跳过已存在的
232	  if (fs.existsSync(filePath)) {
233	    console.log(`  SKIP (已存在): ${cust.name}`);
234	    continue;
235	  }
236	
237	  const frontmatter = `---
238	cid: ${cust.cid}
239	country: ${countryName}
240	heat: NOW
241	stage: ${stage}
242	checked: ${new Date().toISOString().slice(0, 10)}
243	updated: ${new Date().toISOString().slice(0, 10)}
244	---`;
245	
246	  const body = `# ${cust.name}
247	
248	## 画像
249	${countryName} / 未知买家类型 / 阿里巴巴国际站 / ${fmtDate(firstMsgTime)} 首次联系
250	
251	## 最近动态
252	[初稿] 最近5条消息摘要：
253	${generateRecentSummary(recentMsgs)}
254	→ ${cust.reason}
255	
256	## 关键数字
257	[初稿] 自动提取：
258	${extractKeyNumbers(realMsgs) || "（未检测到报价/数量信息）"}
259	
260	## 下一步
261	${generateNextStep(cust, recentMsgs)}
262	
263	## 深度档案
264	无`;
265	
266	  const card = `${frontmatter}\n\n${body}\n`;
267	
268	  fs.writeFileSync(filePath, card, "utf-8");
269	  console.log(`  OK: ${cust.name.padEnd(25)} | ${countryName.padEnd(6)} | ${stage} | ${safeFile}`);
270	  generated++;
271	}
272	
273	console.log(`\n生成: ${generated}张 | 跳过(已存在): ${nowCustomers.length - generated - failed}张 | 失败: ${failed}张`);
274	console.log(`状态卡总数: ${fs.readdirSync(BRIEFS_DIR).filter((f) => f.endsWith(".md")).length}张`);
