1	#!/usr/bin/env node
2	/**
3	 * batch_classify_heat.js — 批量初筛 NOW/SOON/COLD
4	 *
5	 * 读取所有聊天文件，根据最后几条消息自动判定热度：
6	 *   NOW  — 客户最后发消息，等待我方回复
7	 *   SOON — 我方最后发消息，等待客户回复
8	 *   COLD — 超过 90 天无互动
9	 *
10	 * 输出: 分类结果 JSON + 摘要统计
11	 */
12	
13	const fs = require("fs");
14	const path = require("path");
15	
16	const DATA_DIR = path.resolve(__dirname, "..", "data");
17	const CHAT_DIR = path.join(DATA_DIR, "chat_history");
18	const LATEST_PATH = path.join(DATA_DIR, "tm_conversations_latest.json");
19	const OUT_PATH = path.join(DATA_DIR, "heat_classification.json");
20	
21	const NOW_WINDOW_DAYS = 90; // 90天内活跃才考虑 NOW/SOON
22	const CHECK_MSG_COUNT = 10; // 读取最后 N 条消息判断
23	const OUR_UID_MARKER = "2500000853693";
24	
25	// ── 读取会话索引 ──────────────────────────────────────────
26	const latest = JSON.parse(fs.readFileSync(LATEST_PATH, "utf-8"));
27	const conversations = latest.conversations || [];
28	
29	function isSystemMessage(msg) {
30	  try {
31	    const ext = msg.message?.extension;
32	    if (ext?.systemMessage === true) return true;
33	    const bmi = ext?.basicMessageInfo;
34	    if (typeof bmi === "string" && bmi.includes('"systemMessage":true')) return true;
35	    return false;
36	  } catch {
37	    return false;
38	  }
39	}
40	
41	function getMsgText(msg) {
42	  try { return msg.message?.content?.text?.content || ""; } catch { return ""; }
43	}
44	
45	function getMsgTime(msg) {
46	  try { return msg.message?.createAt || 0; } catch { return 0; }
47	}
48	
49	function getSenderIsUs(msg) {
50	  try { return (msg.message?.sender?.uid || "").includes(OUR_UID_MARKER); } catch { return false; }
51	}
52	
53	function cidToFilename(cidStr) {
54	  const match = cidStr.match(/^(.+)#(\d+)@(\w+)$/);
55	  if (!match) return null;
56	  const [, left, channel, platform] = match;
57	  return `${left}_${channel}_${platform}.json`;
58	}
59	
60	// ── 主逻辑 ──────────────────────────────────────────────────
61	const now = Date.now();
62	const results = [];
63	let skipped = 0;
64	
65	for (const conv of conversations) {
66	  const daysSinceLastContact = Math.round((now - conv.lastContactTime) / 86400000);
67	
68	  // COLD: >90 days
69	  if (daysSinceLastContact > NOW_WINDOW_DAYS) {
70	    results.push({
71	      cid: conv.cid,
72	      name: conv.name,
73	      country: conv.complianceCountryCode || "?",
74	      daysSinceLastContact,
75	      heat: "COLD",
76	      stage: "未知",
77	      lastSender: null,
78	      reason: `超过${NOW_WINDOW_DAYS}天无互动`,
79	    });
80	    continue;
81	  }
82	
83	  // 需要聊天文件判断
84	  const filename = cidToFilename(conv.cid);
85	  if (!filename) { skipped++; continue; }
86	  const filepath = path.join(CHAT_DIR, filename);
87	  if (!fs.existsSync(filepath)) { skipped++; continue; }
88	
89	  let raw;
90	  try {
91	    raw = JSON.parse(fs.readFileSync(filepath, "utf-8"));
92	  } catch {
93	    skipped++;
94	    continue;
95	  }
96	
97	  const messages = raw.messages || [];
98	  const realMsgs = messages.filter((m) => !isSystemMessage(m));
99	
100	  if (realMsgs.length === 0) {
101	    results.push({
102	      cid: conv.cid,
103	      name: conv.name,
104	      country: conv.complianceCountryCode || "?",
105	      daysSinceLastContact,
106	      heat: "COLD",
107	      stage: "未知",
108	      lastSender: null,
109	      reason: "无真实消息",
110	    });
111	    continue;
112	  }
113	
114	  // 消息按时间倒序（最新在前），取前 CHECK_MSG_COUNT 条
115	  const recentMsgs = realMsgs.slice(0, CHECK_MSG_COUNT);
116	
117	  // 找最后一条真实消息的发送方
118	  const lastMsg = recentMsgs[0];
119	  const lastSenderIsUs = getSenderIsUs(lastMsg);
120	  const lastMsgText = getMsgText(lastMsg).substring(0, 150);
121	  const lastMsgTime = getMsgTime(lastMsg);
122	
123	  // 判定阶段
124	  let stage = "需求探索";
125	  const allText = recentMsgs.map((m) => getMsgText(m).toLowerCase()).join(" ");
126	
127	  if (allText.includes("payment") || allText.includes("付款") || allText.includes("deposit") || allText.includes("定金")) {
128	    stage = "待付款";
129	  } else if (allText.includes("shipping") || allText.includes("发货") || allText.includes("tracking") || allText.includes("物流") || allText.includes("提单")) {
130	    stage = "待发货";
131	  } else if (allText.includes("quotation") || allText.includes("报价") || allText.includes("price") || allText.includes("单价") || allText.includes("usd") || allText.includes("$/")) {
132	    stage = "报价已发";
133	  } else if (allText.includes("sample") || allText.includes("样品") || allText.includes("打样")) {
134	    stage = "样品阶段";
135	  } else if (allText.includes("negotiate") || allText.includes("谈判") || allText.includes("discount") || allText.includes("折扣")) {
136	    stage = "谈判中";
137	  }
138	
139	  // 判定热度
140	  let heat;
141	  let reason;
142	
143	  // 检查最后 N 条消息中是否有来有回（客+我交替）
144	  const recentSenders = recentMsgs.map((m) => (getSenderIsUs(m) ? "我" : "客"));
145	  const hasCustomerInRecent = recentSenders.includes("客");
146	  const hasUsInRecent = recentSenders.includes("我");
147	
148	  // 计算活跃度：最近 N 条消息的时间跨度
149	  const recentTimeSpan = recentMsgs.length >= 2
150	    ? (getMsgTime(recentMsgs[0]) - getMsgTime(recentMsgs[recentMsgs.length - 1])) / 86400000
151	    : 999;
152	
153	  if (lastSenderIsUs) {
154	    // 我方最后发言
155	    if (hasCustomerInRecent && recentTimeSpan < 7 && daysSinceLastContact <= 14) {
156	      // 近期有来有回且对话活跃 → 可能需要我方继续推进
157	      heat = "NOW";
158	      reason = `活跃对话中，我方最后发言${Math.round(daysSinceLastContact)}天前，需继续推进`;
159	    } else if (daysSinceLastContact > 30) {
160	      heat = "SOON";
161	      reason = `我方最后回复${Math.round(daysSinceLastContact)}天前，客户长期未回`;
162	    } else {
163	      heat = "SOON";
164	      reason = "等待客户回复";
165	    }
166	  } else {
167	    // 客户最后发言 → 等待我方行动
168	    heat = "NOW";
169	    reason = `客户最后发言${Math.round(daysSinceLastContact)}天前，等待我方回复`;
170	    if (daysSinceLastContact > 7) {
171	      reason += " [超期]";
172	    }
173	  }
174	
175	  results.push({
176	    cid: conv.cid,
177	    name: conv.name,
178	    country: conv.complianceCountryCode || "?",
179	    daysSinceLastContact,
180	    heat,
181	    stage,
182	    lastSender: lastSenderIsUs ? "我" : "客",
183	    lastMsgPreview: lastMsgText,
184	    lastMsgTime: new Date(lastMsgTime).toISOString().slice(0, 10),
185	    reason,
186	  });
187	}
188	
189	// ── 按热度排序 ──────────────────────────────────────────────
190	results.sort((a, b) => {
191	  const heatOrder = { NOW: 0, SOON: 1, COLD: 2 };
192	  const ha = heatOrder[a.heat] ?? 9;
193	  const hb = heatOrder[b.heat] ?? 9;
194	  if (ha !== hb) return ha - hb;
195	  return a.daysSinceLastContact - b.daysSinceLastContact;
196	});
197	
198	// ── 输出 ──────────────────────────────────────────────────
199	const summary = {
200	  total: results.length,
201	  now: results.filter((r) => r.heat === "NOW").length,
202	  soon: results.filter((r) => r.heat === "SOON").length,
203	  cold: results.filter((r) => r.heat === "COLD").length,
204	  skipped,
205	  exportedAt: new Date().toISOString(),
206	};
207	
208	// 写 JSON
209	fs.writeFileSync(OUT_PATH, JSON.stringify({ summary, results }, null, 2), "utf-8");
210	
211	// 打印摘要
212	console.log("═══════════════════════════════════════");
213	console.log("  热度初筛完成");
214	console.log("═══════════════════════════════════════");
215	console.log(`NOW: ${summary.now}人 (等待我方行动)`);
216	console.log(`SOON: ${summary.soon}人 (等待客户行动)`);
217	console.log(`COLD: ${summary.cold}人 (超过90天无互动)`);
218	console.log(`跳过: ${summary.skipped}人 (无聊天文件)`);
219	console.log("");
220	console.log("完整结果: data/heat_classification.json");
221	
222	// 打印 NOW 列表
223	console.log("\n── NOW 客户列表 ──");
224	const nowList = results.filter((r) => r.heat === "NOW");
225	for (const r of nowList) {
226	  console.log(`${r.name.padEnd(25)} | ${r.country.padEnd(4)} | ${String(r.daysSinceLastContact).padStart(3)}天前 | ${r.stage.padEnd(8)} | ${r.lastMsgPreview.substring(0, 80)}`);
227	}
228	
229	console.log("\n── SOON 前20 ──");
230	const soonList = results.filter((r) => r.heat === "SOON").slice(0, 20);
231	for (const r of soonList) {
232	  console.log(`${r.name.padEnd(25)} | ${r.country.padEnd(4)} | ${String(r.daysSinceLastContact).padStart(3)}天前 | ${r.stage.padEnd(8)} | ${r.lastMsgPreview.substring(0, 80)}`);
233	}
