509	async function installLwp(cdpClient, iframeSessionId) {
510	  const expr = `
511	    (function() {
512	      var _send = WebSocket.prototype.send;
513	      var _ae = WebSocket.prototype.addEventListener;
514	
515	      window.__lwpPending = {};
516	      window.__lwpSeq = 0;
517	
518	      WebSocket.prototype.send = function(data) {
519	        if (!window.__lwpWs && this.readyState === 1) {
520	          window.__lwpWs = this;
521	          _ae.call(this, 'message', function(event) {
522	            try {
523	              var raw = typeof event.data === 'string' ? event.data : '';
524	              if (raw.indexOf('"code"') < 0) return;
525	              var parsed = JSON.parse(raw);
526	              var mid = parsed.headers && parsed.headers.mid;
527	              if (mid && window.__lwpPending[mid]) {
528	                var p = window.__lwpPending[mid];
529	                delete window.__lwpPending[mid];
530	                p.resolve(parsed);
531	              }
532	            } catch(e) {}
533	          });
