539	      window.__lwpRequest = function(lwpPath, body) {
540	        return new Promise(function(resolve, reject) {
541	          var ws = window.__lwpWs;
542	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
543	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
544	          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
545	          window.__lwpPending[mid] = { resolve: resolve, reject: reject };
546	          ws.send(req);
547	          setTimeout(function() {
