566	async function sendToTarget(cdpClient, sessionId, id, expression, awaitPromise) {
567	  return new Promise((resolve) => {
568	    const timeout = setTimeout(() => resolve(null), 35000);
569	
570	    const handler = (msg) => {
571	      if (sessionId && msg.sessionId !== sessionId) return;
572	      try {
573	        const m = JSON.parse(msg.message);
574	        if (m.id === id) {
575	          clearTimeout(timeout);
576	          cdpClient.off('Target.receivedMessageFromTarget', handler);
577	          if (m.result?.result?.value !== null && m.result?.result?.value !== undefined) {
578	            resolve(m.result.result.value);
579	          } else if (m.result) {
580	            resolve(m.result);
581	          } else {
582	            resolve(null);
583	          }
584	        }
585	      } catch (e) { clearTimeout(timeout); resolve(null); }
586	    };
587	
588	    cdpClient.on('Target.receivedMessageFromTarget', handler);
589	
590	    cdpClient.send('Target.sendMessageToTarget', {
591	      sessionId: sessionId || cdpClient._sessionId,
592	      message: JSON.stringify({
593	        id,
594	        method: 'Runtime.evaluate',
595	        params: { expression, awaitPromise: !!awaitPromise, returnByValue: true }
596	      })
597	    }).catch(() => { clearTimeout(timeout); resolve(null); });
598	  });
599	}
