56	const tmData = JSON.parse(fs.readFileSync(TM_FILE, 'utf8'));
57	const convs = tmData.conversations || [];
58	
59	const convByName = {};
60	for (const c of convs) {
61	  convByName[(c.name || '').toLowerCase().trim()] = c;
62	}
63	
64	const rows = [];
65	const processed = new Set();
66	
67	// Enhanced rows (P0-P2)
68	for (const e of enhanced) {
69	  const conv = convByName[e.name.toLowerCase()] || {};
70	  const days = e.daysAgo;
71	
72	  let stage = '';
73	  let bottleneck = '';
74	  let nextAction = '';
75	  let priority = '';
76	
77	  if (e.tier === 0) {
78	    priority = '今天';
79	    if (e.hasPI && e.hasAddress && e.hasOrderSignal) {
80	      stage = 'PI已发/待付款';
81	      bottleneck = '等待客户付款确认';
82	      nextAction = '确认PI信息，提醒付款';
83	    } else if (e.customerMsgs > 100 && days <= 2) {
84	      stage = '高频互动-需深挖';
85	      bottleneck = '关系好但长期未转化';
86	      nextAction = '独立对话深度分析';
87	    } else if (e.daysAgo <= 1 && e.customerMsgs > 5) {
88	      stage = '客户活跃-需即时响应';
89	      bottleneck = '有待确认事项';
90	      nextAction = '立即回复客户最后消息';
91	    } else {
92	      stage = '报价已发/选款中';
93	      bottleneck = '客户考虑中';
94	      nextAction = '24h内温和跟进';
95	    }
96	  } else if (e.tier === 1) {
97	    priority = '48h';
98	    if (e.hasPI) {
99	      stage = 'PI相关';
100	      bottleneck = '等客户回应';
101	      nextAction = '48h内跟进确认';
102	    } else {
103	      stage = days <= 3 ? '近期活跃' : '谈判中';
104	      nextAction = '48h内跟进';
105	    }
106	  } else if (e.tier === 2) {
107	    priority = '本周';
108	    stage = days <= 7 ? '观察中' : '待激活';
109	    nextAction = '本周温和跟进';
110	  } else {
111	    priority = '';
112	    stage = days > 30 ? '沉默>30d' : '低活跃';
113	  }
114	
115	  rows.push({
116	    name: e.name,
117	    countryCN: cn(e.country),
118	    tier: 'P' + e.tier,
119	    lastContactDays: days,
120	    msgCount: e.msgCount,
121	    lastMsgDir: e.latestCustMsg && days <= 1 ? '客户' : '我方',
122	    stage,
123	    bottleneck,
124	    nextAction,
125	    followupPriority: priority,
126	    notes: (e.hasPI ? '[PI]' : '') + (e.isCore ? '[核心]' : '') + ' 客' + e.customerMsgs + '/' + e.realMsgs + '条',
127	    cid: e.cid,
128	    filename: e.filename,
129	  });
130	  processed.add(e.name.toLowerCase());
131	}
132	
133	// P3-P4: unmatched
134	for (const conv of convs) {
135	  const nameLow = (conv.name || '').toLowerCase().trim();
136	  if (!nameLow || processed.has(nameLow)) continue;
137	
138	  const days = conv.lastContactTime ? Math.floor((NOW_TS - conv.lastContactTime) / D) : 9999;
139	  let tier = 'P4';
140	  if (days < 30) tier = 'P3';
141	  if (days < 60) tier = 'P4';
142	
143	  rows.push({
144	    name: conv.name || '',
145	    countryCN: cn(conv.complianceCountryCode),
146	    tier,
147	    lastContactDays: days,
148	    msgCount: 0,
149	    lastMsgDir: conv.latestMessage && conv.latestMessage.messageType === 'send' ? '我方' : '',
150	    stage: days > 30 ? '沉默>30d' : '',
151	    bottleneck: '',
152	    nextAction: '',
153	    followupPriority: '',
154	    notes: '',
155	    cid: conv.cid,
156	    filename: '',
157	  });
158	  processed.add(nameLow);
159	}
160	
161	// Sort
162	const tierOrder = { P0: 0, P1: 1, P2: 2, P3: 3, P4: 4 };
163	rows.sort((a, b) => {
164	  const ta = tierOrder[a.tier] || 5;
165	  const tb = tierOrder[b.tier] || 5;
166	  if (ta !== tb) return ta - tb;
167	  return a.lastContactDays - b.lastContactDays;
168	});
169	
170	// Tier counts
171	const tc = { P0: 0, P1: 0, P2: 0, P3: 0, P4: 0 };
172	for (const r of rows) {
173	  if (tc[r.tier] !== undefined) tc[r.tier]++;
174	}
175	
176	// Generate Excel
177	const wb = new ExcelJS.Workbook();
178	const ws = wb.addWorksheet('客户管理看板', { views: [{ state: 'frozen', ySplit: 1 }] });
179	
180	const cols = [
181	  { header: '客户名', key: 'name', width: 24 },
182	  { header: '国家', key: 'countryCN', width: 12 },
183	  { header: '梯队', key: 'tier', width: 7 },
184	  { header: '最后联系(天前)', key: 'lastContactDays', width: 11 },
185	  { header: '总消息', key: 'msgCount', width: 8 },
186	  { header: '最新', key: 'lastMsgDir', width: 7 },
187	  { header: '沟通阶段', key: 'stage', width: 18 },
188	  { header: '卡点', key: 'bottleneck', width: 28 },
189	  { header: '下一步行动', key: 'nextAction', width: 34 },
190	  { header: '跟紧', key: 'followupPriority', width: 8 },
191	  { header: '备注', key: 'notes', width: 28 },
192	];
193	ws.columns = cols;
194	
195	const hr = ws.getRow(1);
196	hr.font = { bold: true, size: 11, color: { argb: 'FFFFFFFF' } };
197	hr.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
198	hr.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
199	hr.height = 34;
200	
201	const tierFills = { P0: 'FFC00000', P1: 'FFED7D31', P2: 'FFFFC000', P3: 'FF4472C4', P4: 'FFA5A5A5' };
202	
203	for (const row of rows) {
204	  const r = ws.addRow(row);
205	  r.height = 21;
206	  if (row.tier && tierFills[row.tier]) {
207	    const cell = r.getCell('tier');
208	    cell.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 11 };
209	    cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: tierFills[row.tier] } };
210	    cell.alignment = { horizontal: 'center' };
211	  }
212	  if (row.lastContactDays > 30) r.font = { color: { argb: 'FFA0A0A0' } };
213	  if (row.stage) r.getCell('stage').font = { bold: true };
214	  if (row.tier === 'P0') r.getCell('name').font = { bold: true };
215	}
216	
217	ws.autoFilter = { from: { row: 1, column: 1 }, to: { row: rows.length + 1, column: cols.length } };
218	
219	// Summary
220	const sws = wb.addWorksheet('统计');
221	sws.columns = [
222	  { header: '指标', key: 'metric', width: 22 },
223	  { header: '数值', key: 'value', width: 26 },
224	];
225	
226	const a24 = rows.filter(r => r.lastContactDays < 1).length;
227	const a7d = rows.filter(r => r.lastContactDays < 7).length;
228	const a30d = rows.filter(r => r.lastContactDays < 30).length;
229	const s30d = rows.filter(r => r.lastContactDays >= 30).length;
230	
231	sws.addRows([
232	  { metric: '生成时间', value: NOW.toISOString().slice(0, 16).replace('T', ' ') },
233	  { metric: '客户总数', value: rows.length },
234	  { metric: '24h活跃', value: a24 },
235	  { metric: '7d活跃', value: a7d },
236	  { metric: '30d内活跃', value: a30d },
237	  { metric: '>30d沉默', value: s30d },
238	  { metric: '', value: '' },
239	  ...Object.entries(tc).map(([k, v]) => ({ metric: '梯队 ' + k, value: v })),
240	  { metric: '', value: '' },
241	  { metric: '分类规则', value: 'P0=PI/付款/下单/高频 | P1=近期活跃+信号 | P2=7d内互动 | P3=30d内 | P4=>30d沉默' },
242	]);
243	
244	const sh = sws.getRow(1);
245	sh.font = { bold: true, color: { argb: 'FFFFFFFF' } };
246	sh.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
247	
248	const outFile = path.join(REPORTS_DIR, '客户管理看板_' + DATE_STR + '_' + TIME_STR + '.xlsx');
249	if (!fs.existsSync(REPORTS_DIR)) fs.mkdirSync(REPORTS_DIR, { recursive: true });
250	wb.xlsx.writeFile(outFile).then(() => {
251	  console.log('Generated: ' + outFile);
252	  console.log('Tiers: P0=' + tc.P0 + ' P1=' + tc.P1 + ' P2=' + tc.P2 + ' P3=' + tc.P3 + ' P4=' + tc.P4);
253	  console.log('24h:' + a24 + ' 7d:' + a7d + ' 30d:' + a30d + ' >30d:' + s30d);
254	}).catch(err => { console.error(err); process.exit(1); });
