1	/**
2	 * OKKI 交易 → 销售订单 同步脚本 v4
3	 * 用法：node scripts/sync_orders.js
4	 */
5	const { chromium } = require('playwright');
6	const fs = require('fs');
7	const path = require('path');
8	
9	const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
10	const CDP_URL = 'http://localhost:9222';
11	const DATA_DIR = path.join(__dirname, '..', 'data');
12	
13	function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
14	
15	async function main() {
16	  let browser, page;
17	
18	  // CDP 连接
19	  let useCdp = false;
20	  try {
21	    const http = require('http');
22	    const cdpOk = await new Promise(r => {
23	      http.get('http://127.0.0.1:9222/json/version', res => r(true)).on('error', () => r(false));
24	    });
25	    if (cdpOk) {
26	      browser = await chromium.connectOverCDP(CDP_URL);
27	      const pages = browser.contexts()[0].pages();
28	      page = pages[0];
29	      useCdp = true;
30	      log('CDP 已连接');
31	    }
32	  } catch (e) {}
33	
34	  if (!useCdp) {
35	    log('启动 Chrome...');
36	    browser = await chromium.launchPersistentContext(PROFILE, {
37	      channel: 'chrome', headless: false,
38	      viewport: { width: 1440, height: 900 },
39	      args: ['--remote-debugging-port=9222'],
40	    });
41	    page = await browser.newPage();
42	  }
43	
44	  // 导航到订单页
45	  log('导航到销售订单页...');
46	  await page.goto('https://crm.xiaoman.cn/order', { waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
47	  await new Promise(r => setTimeout(r, 2000));
48	
49	  // 等登录
50	  if (page.url().includes('login')) {
51	    log('请登录 OKKI...');
52	    const startTime = Date.now();
53	    while (page.url().includes('login')) {
54	      await new Promise(r => setTimeout(r, 2000));
55	      if (Date.now() - startTime > 5 * 60 * 1000) {
56	        log('登录超时');
57	        await browser.close();
58	        return;
59	      }
60	    }
61	    log('已登录，重新导航...');
62	    await page.goto('https://crm.xiaoman.cn/order', { waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
63	    await new Promise(r => setTimeout(r, 3000));
64	  }
65	
66	  log('当前 URL: ' + page.url());
67	
68	  // 等待虚拟列表渲染
69	  await page.waitForSelector('.vue-recycle-scroller__item-view', { timeout: 10000 }).catch(() => {});
70	  await new Promise(r => setTimeout(r, 1500));
71	
72	  // 日期标准化
73	  function normalizeDate(dateStr) {
74	    if (!dateStr) return '';
75	    const now = new Date();
76	    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
77	    if (dateStr === '昨天') { const d = new Date(today); d.setDate(d.getDate() - 1); return d.toISOString().slice(0, 10); }
78	    if (dateStr === '今天') return today.toISOString().slice(0, 10);
79	    if (dateStr === '前天') { const d = new Date(today); d.setDate(d.getDate() - 2); return d.toISOString().slice(0, 10); }
80	    const mmdd = dateStr.match(/(\d{1,2})月(\d{1,2})日/);
81	    if (mmdd) {
82	      const m = parseInt(mmdd[1]), d = parseInt(mmdd[2]);
83	      const year = (m > now.getMonth() + 1) ? now.getFullYear() - 1 : now.getFullYear();
84	      return `${year}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
85	    }
86	    return dateStr;
87	  }
88	
89	  // 提取当前页订单数据
90	  function extractPageOrders() {
91	    return page.evaluate(() => {
92	      const result = [];
93	      const rows = document.querySelectorAll('.vue-recycle-scroller__item-view');
94	      rows.forEach(row => {
95	        // 跳过表头行 (class 含 row-item__hidden_border_top)
96	        const rowItem = row.querySelector('.row-item');
97	        if (rowItem && rowItem.classList.contains('row-item__hidden_border_top')) return;
98	        const cells = row.querySelectorAll('.cell-inner');
99	        if (cells.length < 8) return;
100	        const texts = Array.from(cells).map(c => c.textContent?.trim() || '');
101	        // DOM实测字段: [0]checkbox空 [1]保障图标空 [2]订单号前半 [3]订单号后半 [4]日期 [5]金额 [6]客户 [7]状态 [8]ERP [9]空 [10]空
102	        const orderNo = (texts[2] || '') + (texts[3] || '');
103	        if (orderNo.length >= 15 && /^\d{15,}$/.test(orderNo)) {
104	          result.push({
105	            orderNo: orderNo,
106	            orderDate: texts[4],
107	            amount: texts[5],
108	            customer: texts[6],
109	            status: texts[7],
110	            erpStatus: texts[8] || '',
111	          });
112	        }
113	      });
114	      return result;
115	    });
116	  }
117	
118	  // 提取第1页
119	  log('提取第1批...');
120	  let orders = await extractPageOrders();
121	  log(`  第1批: ${orders.length} 条`);
122	
123	  // 虚拟列表滚动加载更多
124	  const seen = new Set(orders.map(o => o.orderNo));
125	  const vlSelector = '.vue-recycle-scroller';
126	  for (let scroll = 1; scroll <= 8; scroll++) {
127	    const vl = await page.$(vlSelector);
128	    if (!vl) { log('  未找到滚动容器'); break; }
129	    const box = await vl.boundingBox();
130	    if (!box) { log('  滚动容器不可见'); break; }
131	    await page.mouse.move(box.x + box.width / 2, box.y + box.height / 2);
132	    await page.mouse.wheel(0, 800);
133	    await new Promise(r => setTimeout(r, 2000));
134	    const more = await extractPageOrders();
135	    let added = 0;
136	    for (const o of more) {
137	      if (!seen.has(o.orderNo)) { seen.add(o.orderNo); orders.push(o); added++; }
138	    }
139	    log(`  滚动${scroll}次: +${added} 条 (累计 ${orders.length})`);
140	    if (added === 0) break;
141	  }
142	
143	  // 翻页（okki-pagination）
144	  for (let pg = 2; pg <= 10; pg++) {
145	    const clicked = await page.evaluate((pgNum) => {
146	      const items = document.querySelectorAll('.okki-pagination-item');
147	      for (const el of items) {
148	        if (el.textContent?.trim() === String(pgNum) && el.offsetParent !== null) { el.click(); return true; }
149	      }
150	      const next = document.querySelector('.okki-pagination-next:not(.okki-pagination-disabled)');
151	      if (next && next.offsetParent !== null) { next.click(); return true; }
152	      return false;
153	    }, pg);
154	    if (!clicked) break;
155	    log(`  翻到第${pg}页...`);
156	    await page.waitForSelector('.vue-recycle-scroller__item-view', { timeout: 8000 }).catch(() => {});
157	    await new Promise(r => setTimeout(r, 1500));
158	    const pageOrders = await extractPageOrders();
159	    let added = 0;
160	    for (const o of pageOrders) {
161	      if (!seen.has(o.orderNo)) { seen.add(o.orderNo); orders.push(o); added++; }
162	    }
163	    log(`  第${pg}页: +${added} 条 (累计 ${orders.length})`);
164	    if (added === 0) break;
165	  }
166	
167	  log(`共提取 ${orders.length} 条订单`);
168	
169	  // 日期标准化
170	  for (const o of orders) { o.orderDate = normalizeDate(o.orderDate); }
171	
172	  // 保存
173	  const outPath = path.join(DATA_DIR, 'orders_latest.json');
174	  const output = { exportedAt: new Date().toISOString(), total: orders.length, orders };
175	  fs.writeFileSync(outPath, JSON.stringify(output, null, 2));
176	  log(`已保存: ${outPath}`);
177	
178	  // 统计
179	  const statusCounts = {};
180	  for (const o of orders) { statusCounts[o.status] = (statusCounts[o.status] || 0) + 1; }
181	  log('订单状态统计:');
182	  for (const [k, v] of Object.entries(statusCounts)) { log(`  ${k}: ${v}`); }
183	
184	  const delivered = orders.filter(o => o.status === '交易成功');
185	  log(`\n交易成功客户 (${delivered.length}人):`);
186	  for (const o of delivered) { log(`  ${o.customer} | ${o.amount} | ${o.orderDate}`); }
187	
188	  log('完成。浏览器保持打开，供后续使用');
189	}
190	
191	main().catch(e => { console.error(e); process.exit(1); });
