1	#!/usr/bin/env node
2	/**
3	 * validate_output.js — AI 输出话术自动扫描
4	 *
5	 * 扫描 AI 草拟的回复话术，标记潜在风险点。
6	 * 不拦截输出，只标记提醒。用户是最终决定者。
7	 *
8	 * 用法:
9	 *   echo "回复文本" | node scripts/validate_output.js [--cid=<cid>]
10	 *   node scripts/validate_output.js --file=<path> [--cid=<cid>]
11	 *
12	 * 检测项:
13	 *   1. 具体金额 → 提醒确认
14	 *   2. 日期承诺 → 提醒确认
15	 *   3. 语言与客户最后消息不一致 → 提醒
16	 *   4. MOQ/数量决定 → 提醒确认
17	 *   5. 我方延迟回复 >24h 且未致歉 → 提醒
18	 */
19	
20	const fs = require("fs");
21	const path = require("path");
22	
23	// ── 参数解析 ──────────────────────────────────────────────
24	const args = process.argv.slice(2);
25	const getArg = (name) => {
26	  const prefix = `--${name}=`;
27	  const found = args.find((a) => a.startsWith(prefix));
28	  return found ? found.slice(prefix.length) : null;
29	};
30	
31	const cid = getArg("cid");
32	const filePath = getArg("file");
33	
34	// ── 读取输入 ──────────────────────────────────────────────
35	let inputText = "";
36	
37	if (filePath) {
38	  if (!fs.existsSync(filePath)) {
39	    console.error(`文件不存在: ${filePath}`);
40	    process.exit(1);
41	  }
42	  inputText = fs.readFileSync(filePath, "utf-8");
43	} else {
44	  // 从 stdin 读取
45	  inputText = fs.readFileSync(0, "utf-8"); // fd 0 = stdin
46	}
47	
48	if (!inputText.trim()) {
49	  console.error("未检测到输入文本。用法: echo '回复内容' | node validate_output.js");
50	  process.exit(1);
51	}
52	
53	// ── 规则库 ────────────────────────────────────────────────
54	
55	const findings = [];
56	
57	// 1. 金额检测
58	const amountPatterns = [
59	  { pattern: /\$\s*\d+[\d,]*\.?\d*/g, desc: "美元金额 ($)" },
60	  { pattern: /USD\s*\d+[\d,]*\.?\d*/gi, desc: "USD 金额" },
61	  { pattern: /\d+[\d,]*\.?\d*\s*(美元|美金)/g, desc: "人民币金额" },
62	  { pattern: /\d+[\d,]*\.?\d*\s*(欧元|英镑|日元)/g, desc: "外币金额" },
63	  { pattern: /\d+[\d,]*\.?\d*\s*元[\/\s]*(件|个|套|条|包|箱)/g, desc: "单价金额" },
64	  { pattern: /\d+[\d,]*\.?\d*\s*%/g, desc: "折扣百分比" },
65	];
66	for (const { pattern, desc } of amountPatterns) {
67	  const matches = inputText.match(pattern);
68	  if (matches) {
69	    for (const m of matches) {
70	      findings.push({ type: "金额", severity: "⚠", detail: `${desc}: "${m.trim()}" → 请确认金额无误`, source: "rule:amount" });
71	    }
72	  }
73	}
74	
75	// 2. 日期承诺检测
76	const datePatterns = [
77	  // 中文
78	  { pattern: /\d+\s*天[内之]/g, desc: "天数承诺" },
79	  { pattern: /今天|明天|后天|下周[一二三四五六日]?|本周[一二三四五六日]?/g, desc: "具体日期承诺" },
80	  { pattern: /当天[发寄送出货]/g, desc: "当天发货承诺" },
81	  { pattern: /立刻[发寄送出给排安]/g, desc: "立刻行动承诺" },
82	  { pattern: /马上[发寄送出给排安]/g, desc: "马上行动承诺" },
83	  { pattern: /(\d+)\s*(个?小?时|工作日|周|月)\s*[内之]/g, desc: "时间段承诺" },
