206	function getContextInfo(cidStr) {
207	  try {
208	    const DATA_DIR = path.resolve(__dirname, "..", "data");
209	    const CHAT_DIR = path.join(DATA_DIR, "chat_history");
210	
211	    const match = cidStr.match(/^(.+)#(\d+)@(\w+)$/);
212	    if (!match) return null;
213	    const [, left, channel, platform] = match;
214	    const filename = `${left}_${channel}_${platform}.json`;
215	    const filepath = path.join(CHAT_DIR, filename);
216	
217	    if (!fs.existsSync(filepath)) return null;
218	
219	    const raw = JSON.parse(fs.readFileSync(filepath, "utf-8"));
220	    const messages = raw.messages || [];
221	
222	    // 过滤系统消息
223	    function isSys(m) {
224	      try {
225	        const ext = m.message?.extension;
226	        if (ext?.systemMessage === true) return true;
227	        const bmi = ext?.basicMessageInfo;
228	        if (typeof bmi === "string" && bmi.includes('"systemMessage":true')) return true;
229	        return false;
230	      } catch { return false; }
231	    }
232	    const realMsgs = messages.filter((m) => !isSys(m));
233	
234	    // 找客户最后一条消息的语言
235	    // 消息按时间倒序（最新在前），从索引 0 向前扫
236	    let customerLang = null;
237	    for (let i = 0; i < realMsgs.length; i++) {
238	      const uid = realMsgs[i].message?.sender?.uid || "";
239	      if (!uid.includes("2500000853693")) {
240	        const text = realMsgs[i].message?.content?.text?.content || "";
241	        if (text.trim()) {
242	          const lang = detectLanguage(text);
243	          if (lang) {
244	            customerLang = lang;
245	            break;
246	          }
247	        }
248	      }
249	    }
250	
251	    // 找我方最后一条消息的时间（最新在前，从索引 0 开始）
252	    let ourLastTime = null;
253	    for (let i = 0; i < realMsgs.length; i++) {
254	      const uid = realMsgs[i].message?.sender?.uid || "";
255	      if (uid.includes("2500000853693")) {
256	        ourLastTime = realMsgs[i].message?.createAt || null;
257	        break;
258	      }
259	    }
260	
261	    const hoursSinceOurLast = ourLastTime
262	      ? (Date.now() - ourLastTime) / (1000 * 60 * 60)
263	      : null;
264	
265	    return {
266	      name: raw.name || null,
267	      customerLang,
268	      ourLastTime,
269	      hoursSinceOurLast,
270	    };
271	  } catch (e) {
272	    return null;
273	  }
274	}
