276	function detectLanguage(text) {
277	  if (!text || !text.trim()) return null;
278	
279	  // 统计各类字符
280	  let cjk = 0;
281	  let arabic = 0;
282	  let french = 0;
283	  let latin = 0;
284	
285	  for (const ch of text) {
286	    const code = ch.charCodeAt(0);
287	    if ((code >= 0x4E00 && code <= 0x9FFF) || (code >= 0x3400 && code <= 0x4DBF)) {
288	      cjk++;
289	    } else if (code >= 0x0600 && code <= 0x06FF) {
290	      arabic++;
291	    } else if (code >= 0x0041 && code <= 0x007A) {
292	      latin++;
293	      // 法语特征词
294	      if (/[eèéêë]/.test(ch)) french++;
295	    }
296	  }
297	
298	  const total = cjk + arabic + latin;
299	  if (total === 0) return null;
300	
301	  if (cjk / total > 0.15) return "zh";
302	  if (arabic / total > 0.10) return "ar";
303	
304	  // 法语特征词检测
305	  const frenchWords = /\b(je|tu|nous|vous|le|la|les|est|sont|dans|pour|avec|sur|pas|une|très|bien|merci|bonjour|salut|comment|pourquoi|quand|quoi|parce|aussi|mais|dans|peut|faire|avoir|être|aller|pouvoir|devoir|vouloir|celui|celle|ceux|mon|ton|son|notre|votre|leur)\b/gi;
306	  const frenchMatch = text.match(frenchWords);
307	  if (frenchMatch && frenchMatch.length >= 2) return "fr";
308	
309	  if (latin / total > 0.5) return "en";
310	
311	  return "mixed";
312	}
