387	    }
388	    case '报价已发': {
389	      const d = parseDate(bl.S2);
390	      if (!d) break;
391	      const days = daysBetween(d, t);
392	      if (days < 1) break;
393	      const hitIdx = rhythmHit(days, RHYTHM.S2);
394	      if (hitIdx >= 0) {
395	        const cumulative = RHYTHM.S2.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
396	        factors.push({ factor: 'S2 该追问了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S2 });
397	      }
398	      break;
399	    }
400	    case '谈判中': {
401	      const d = parseDate(bl.S3);
402	      if (!d) break;
403	      const days = daysBetween(d, t);
404	      if (days < 1) break;
405	      const hitIdx = rhythmHit(days, RHYTHM.S3);
406	      if (hitIdx >= 0) {
407	        const cumulative = RHYTHM.S3.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
408	        factors.push({ factor: 'S3 该推进了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S3 });
409	      }
410	      break;
411	    }
412	    case '待付款': {
413	      const d = parseDate(bl.S4);
414	      if (!d) break;
415	      const days = daysBetween(d, t);
416	      if (days < 1) break;
417	      const hitIdx = rhythmHit(days, RHYTHM.S4);
418	      if (hitIdx >= 0) {
419	        const cumulative = RHYTHM.S4.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
