448	      if (!d) break;
449	      const days = daysBetween(d, t);
450	      const interval = s6Interval(meta);
451	      if (days >= 1 && days % interval === 0) {
452	        factors.push({ factor: 'S6 该更新物流了', days, rhythmDay: days, baseline: bl.S6, interval });
453	      }
454	      break;
455	    }
456	    case '已签收': {
457	      if (bl.S7a) {
458	        const d = parseDate(bl.S7a);
459	        if (d) {
460	          const days = daysBetween(d, t);
