462	            const hitIdx = rhythmHit(days, RHYTHM.S7a);
463	            if (hitIdx >= 0) {
464	              const cumulative = RHYTHM.S7a.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
465	              factors.push({ factor: 'S7a 该回访了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S7a });
466	            }
