479	              factors.push({ factor: 'S7b 该推返单了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S7b });
480	            }
481	          }
482	        }
483	      }
484	      break;
485	    }
486	    case '售后': {
487	      const d = parseDate(bl.S8);
488	      if (!d) break;
489	      const days = daysBetween(d, t);
490	      if (days < 1) break;
491	      const hitIdx = rhythmHit(days, RHYTHM.S8);
492	      if (hitIdx >= 0) {
493	        const cumulative = RHYTHM.S8.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
494	        factors.push({ factor: 'S8 该收尾了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S8 });
495	      }
496	      break;
497	    }
498	    case '待返单': {
499	      if (bl.S9) {
500	        const d = parseDate(bl.S9);
501	        if (d) {
502	          const days = daysBetween(d, t);
503	          if (days >= 1) {
504	            const rhythm = meta.customer_type === '样品单' ? RHYTHM.S9_sample : RHYTHM.S9_bulk;
505	            const hitIdx = rhythmHit(days, rhythm);
506	            if (hitIdx >= 0) {
