508	              factors.push({ factor: 'S9 该接触了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S9 });
509	            }
510	          }
511	        }
512	      }
513	      break;
514	    }
515	  }
516	
517	  return factors;
518	}
