520	/** 因子命中统计 */
521	function summarizeFactors(soonCustomers) {
522	  const factorCounts = {};
523	  for (const c of soonCustomers) {
524	    for (const f of c.factors) {
525	      const key = f.factor.split('(')[0].trim();
526	      factorCounts[key] = (factorCounts[key] || 0) + 1;
527	    }
528	  }
529	  return factorCounts;
530	}
