171	  for (const m of msgs) {
172	    if (isSys((m.message || m).content)) continue;
173	    const msg = m.message || m;
174	    const uid = msg.sender && msg.sender.uid || '';
175	    const text = getText(msg.content, msg.searchableContent);
176	    if (!text.trim()) continue;
177	    const date = msg.createAt ? new Date(msg.createAt).toISOString().slice(0, 10) : '?';
178	    const who = uid === OUR_UID ? '[我方]' : '[客户]';
179	    real.push(who + ' ' + date + ' | ' + text.substring(0, 200));
