191	  if (!name) return null;
192	  const n = name.toLowerCase().trim();
193	  // 精确匹配
194	  for (const o of ordersData.orders) {
195	    if ((o.customer || '').toLowerCase().trim() === n) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
196	  }
197	  // 模糊匹配：客户名包含公司名或反之
198	  for (const o of ordersData.orders) {
199	    const cn = (o.customer || '').toLowerCase().trim();
200	    if (!cn) continue;
201	    if (n.includes(cn) || cn.includes(n)) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
202	  }
203	  return null;
204	}
